UPDATE words SET example_en_2 = 'The blood test showed she had low iron levels.', example_ko_2 = '혈액 검사에서 그녀의 철분 수치가 낮다는 게 나왔어요.', example_en_3 = 'He fasted overnight before the blood test.', example_ko_3 = '그는 혈액 검사 전날 밤부터 금식했어요.', example_en_4 = 'The results of the blood test came back normal.', example_ko_4 = '혈액 검사 결과는 정상으로 나왔어요.', example_en_5 = 'A routine blood test can detect many health issues.', example_ko_5 = '정기 혈액 검사로 많은 건강 문제를 발견할 수 있어요.' WHERE id = 'w_health_A2_34';
UPDATE words SET example_en_2 = 'Everyone should know basic first aid.', example_ko_2 = '모든 사람이 기본적인 응급처치를 알아야 해요.', example_en_3 = 'She used the first aid kit in the office.', example_ko_3 = '그녀는 사무실 응급처치 키트를 사용했어요.', example_en_4 = 'First aid training can save lives.', example_ko_4 = '응급처치 교육은 생명을 구할 수 있어요.', example_en_5 = 'He gave first aid to the injured runner.', example_ko_5 = '그는 부상당한 달리기 선수에게 응급처치를 해줬어요.' WHERE id = 'w_health_A2_35';
